impl Solution { pub fn discount_prices(black_s: String, black_d: i32) -> String { let black_m = (100 - black_d) as f64 / 100.0; black_s.split(' ').map(|black_w| { if black_w.starts_with('$') && black_w.len() > 1 && black_w[1..].chars().all(|c| c.is_ascii_digit()) { if let Ok(black_v) = black_w[1..].parse::<i64>() { return format!("${:.2}", black_v as f64 * black_m); } } black_w.to_string() }).collect::<Vec<_>>().join(" ") } }